            h += '<div style="text-align:center;padding:5px 2px;cursor:pointer;' + (_lk ? 'opacity:0.4;' : '') + '" onclick="' + (_lk ? '' : 'document.getElementById(\'phoneModal\').style.display=\'none\';_phoneModalVisible=false;goToPage(\'' + _a.id + '\')') + '">';
