function _hsAction(hs) {
    if (hs.action === 'phone') { _exitSceneToUI(); }
    else if (hs.action === 'sleep') { _endDay(); }
    else if (hs.action === 'nav') {
        if (hs.target === '_nav') _showSceneNavModal();
        else if (hs.target === '_elevator') _showElevatorModal();
    }
    else if (hs.action === 'scene') { _navigateScene(hs.target); }
    else if (hs.action === 'app') { goToPage(hs.target); }
}

function renderScenePage(container) {
    window._inSceneMode = true;
    var sceneId = gameState._currentScene || _getHomeScene();
    var scene = SCENES[sceneId];
    if (!scene) { sceneId = _getHomeScene(); scene = SCENES[sceneId]; }
    if (!scene) { renderHomePage(container); return; }
    if (typeof BGMManager !== 'undefined') {
        if (sceneId.indexOf('practice') !== -1 || sceneId.indexOf('train') !== -1) BGMManager.play('practice');
        else if (sceneId.indexOf('company') !== -1 || sceneId.indexOf('office') !== -1) BGMManager.play('company');
        else if (sceneId.indexOf('dorm') !== -1) BGMManager.play('dorm');
        else if (sceneId.indexOf('stage') !== -1 || sceneId.indexOf('concert') !== -1) BGMManager.play('stage');
    }

    var locationName = scene.name;
    if (scene.floor) locationName = scene.floor + 'F ' + scene.name;
    var dayInfo = _getGameDayDisplay();

    var hotspotsHtml = '';
    for (var hi = 0; hi < scene.hotspots.length; hi++) {
        var hs = scene.hotspots[hi];
        var act = '';
        if (hs.action === 'phone') act = '_exitSceneToUI()';
        else if (hs.action === 'sleep') act = '_endDay()';
        else if (hs.action === 'nav' && hs.target === '_nav') act = '_showSceneNavModal()';
        else if (hs.action === 'nav' && hs.target === '_elevator') act = '_showElevatorModal()';
        else if (hs.action === 'scene') act = '_navigateScene(\'' + hs.target + '\')';
        else if (hs.action === 'app') act = 'goToPage(\'' + hs.target + '\')';

        hotspotsHtml += '<div onclick="try{' + act + '}catch(e){alert(\'Error:\'+e.message)}" style="position:absolute;left:' + hs.x + '%;top:' + hs.y + '%;transform:translate(-50%,-50%);cursor:pointer;text-align:center;z-index:10;-webkit-tap-highlight-color:transparent;">';
        hotspotsHtml += '<div class="scene-hs">';
        hotspotsHtml += getIcon(hs.icon);
        hotspotsHtml += '</div>';
        hotspotsHtml += '<div class="scene-hs-label">' + hs.label + '</div>';
        hotspotsHtml += '</div>';
    }

    container.innerHTML = '<style>.scene-hs{width:44px;height:44px;border-radius:12px;background:rgba(255,255,255,0.12);backdrop-filter:blur(10px);display:flex;align-items:center;justify-content:center;margin:0 auto 2px;box-shadow:0 2px 8px rgba(0,0,0,0.2);border:1px solid rgba(255,255,255,0.18);transition:transform .15s,background .15s;}.scene-hs:active{transform:scale(0.9);background:rgba(255,255,255,0.25);}.scene-hs svg{width:20px;height:20px;stroke:white;fill:none;}.scene-hs-label{font-size:8px;color:rgba(255,255,255,0.75);text-shadow:0 1px 3px rgba(0,0,0,0.7);white-space:nowrap;font-weight:500;letter-spacing:0.3px;}.scene-day{position:absolute;top:max(6px,env(safe-area-inset-top));left:8px;z-index:20;background:rgba(0,0,0,0.3);backdrop-filter:blur(6px);border-radius:6px;padding:2px 6px;font-size:9px;color:rgba(255,255,255,0.7);font-weight:500;}.scene-loc{position:absolute;top:max(6px,env(safe-area-inset-top));right:8px;z-index:20;background:rgba(0,0,0,0.3);backdrop-filter:blur(6px);border-radius:6px;padding:2px 6px;font-size:9px;color:rgba(255,255,255,0.7);font-weight:500;}</style>'
        + '<div style="position:fixed;top:0;left:0;right:0;bottom:0;overflow:hidden;z-index:1;">'
        + '<div style="position:absolute;top:0;left:0;right:0;bottom:0;background-image:url(\'' + scene.img + '\');background-size:cover;background-position:center;"></div>'
        + '<div class="scene-day">\u7b2c' + dayInfo.day + '\u5929 ' + dayInfo.weekDay + '</div>'
        + '<div class="scene-loc">' + locationName + '</div>'
        + '<div style="position:absolute;top:0;left:0;right:0;bottom:0;z-index:5;">' + hotspotsHtml + (typeof _v2GetSceneNpcHtml==='function'?_v2GetSceneNpcHtml(sceneId):'') + '</div>'
        + '<div style="position:absolute;bottom:max(8px,env(safe-area-inset-bottom));left:50%;transform:translateX(-50%);z-index:20;display:flex;gap:14px;background:rgba(0,0,0,0.4);backdrop-filter:blur(8px);border-radius: 12px;padding:6px 16px;">' + '<div onclick="_exitSceneToUI()" style="color:white;cursor:pointer;display:flex;align-items:center;gap:3px;font-size:10px;-webkit-tap-highlight-color:transparent;padding:3px 0;"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="5" y="2" width="14" height="20" rx="2" ry="2"></rect></svg>手机</div>' + '<div onclick="_showSceneNavModal()" style="color:white;cursor:pointer;display:flex;align-items:center;gap:3px;font-size:10px;-webkit-tap-highlight-color:transparent;padding:3px 0;"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="3 11 13 2 13 8 22 8 22 14 13 14 13 20 3 11"></polygon></svg>导航</div>' + '<div onclick="goToPage(&#39;me&#39;)" style="color:white;cursor:pointer;display:flex;align-items:center;gap:3px;font-size:10px;-webkit-tap-highlight-color:transparent;padding:3px 0;"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="7" r="4"></circle><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path></svg>我的</div>' + '</div>'
        + '</div>'
}

