            var lockReasons = [];
            if (statVal < 105) lockReasons.push('需' + s.name + '≥105（当前' + statVal + '）');
            if (gameState.money < 300) lockReasons.push('金币不足300（当前' + gameState.money + '）');
            var lockReason = lockReasons.length > 0 ? lockReasons.join(' · ') : '';
