function getAITotalUsageToday() {
    var d = new Date();
    var dateStr = d.getFullYear() + '' + ('0' + (d.getMonth() + 1)).slice(-2) + '' + ('0' + d.getDate()).slice(-2);
    if (!gameState.aiUsage) gameState.aiUsage = {};
    var total = 0;
    var aiApps = ['kakaotalk', 'bubble', 'dating', 'ins', 'tiktok', 'weverse', 'live', 'contacts', 'sns', 'fancommunity'];
    for (var i = 0; i < aiApps.length; i++) {
        var key = aiApps[i] + '_' + dateStr;
        total += (gameState.aiUsage[key] || 0);
    }
    return total;
}

function getAIUsageToday(appId) {
    var d = new Date();
    var dateStr = d.getFullYear() + '' + ('0' + (d.getMonth() + 1)).slice(-2) + '' + ('0' + d.getDate()).slice(-2);
    var key = appId + '_' + dateStr;
    if (!gameState.aiUsage) gameState.aiUsage = {};
    return gameState.aiUsage[key] || 0;
}

function getAIMaxTotalToday() {
    // VIP tier-based limits
    var vipTier = gameState.vipTier || null;
    if (!vipTier) { try { vipTier = JSON.parse(localStorage.getItem('myidol_saves_' + localStorage.getItem('myidol_current_account')) || '{}').vipTier; } catch(e) {} }
    var base = 3;
    if (vipTier === 'premium') base = 80;
    else if (vipTier === 'advanced') base = 40;
    else if (vipTier === 'basic') base = 15;
    var bonus = gameState._bonusAiToday || 0;
    return base + bonus;
}

function canUseAIToday() {
    return getAITotalUsageToday() < getAIMaxTotalToday();
}

