// V1.7: Get personality-based gift reaction
function getGiftReaction(npcName, giftName) {
    var npc = null;
    if (Object.keys(COMPANIES).length === 0 && window.COMPANIES && Object.keys(window.COMPANIES).length > 0) { COMPANIES = window.COMPANIES; }
    var compKeys = Object.keys(COMPANIES);
    for (var ci = 0; ci < compKeys.length && !npc; ci++) {
        var comp = COMPANIES[compKeys[ci]];
        var gKeys = Object.keys(comp.groups);
        for (var gi = 0; gi < gKeys.length && !npc; gi++) {
            var grp = comp.groups[gKeys[gi]];
            for (var mi = 0; mi < grp.members.length; mi++) {
                if (grp.members[mi].name === npcName) {
                    npc = grp.members[mi];
                    break;
                }
            }
        }
    }
    if (!npc) return null;
    var personality = (npc.personality && npc.personality.join) ? npc.personality[0] : (npc.personality || '温柔');
    // Check if gift matches a special category
    var giftLower = giftName.toLowerCase ? giftName.toLowerCase() : giftName;
    var matchedKey = '';
    var keys = Object.keys(_specialGiftReactions);
    for (var ki = 0; ki < keys.length; ki++) {
        if (giftLower.indexOf(keys[ki]) >= 0) {
            matchedKey = keys[ki];
            break;
        }
    }
    var love = (gameState.npc好感度 && gameState.npc好感度[npcName]) || 0;
    var reaction = '';
    if (matchedKey) {
        reaction = _specialGiftReactions[matchedKey][personality] || _specialGiftReactions[matchedKey]['温柔'];
    } else {
        reaction = _defaultGiftReactions[personality] || _defaultGiftReactions['温柔'];
    }
    // High love bonus reaction
    if (love >= 80) {
        reaction += ' ...跟你在一起好安心。';
    } else if (love >= 60) {
        reaction += ' 你对我真的很好。';
    }
    return reaction;
}

function render恋爱Page(container) {
    try {
    if (!gameState.npc好感度) gameState.npc好感度 = {};
    if (!gameState.loveChats) gameState.loveChats = {};
    if (!gameState.loveUnread) gameState.loveUnread = {};
    if (window.COMPANIES && Object.keys(window.COMPANIES).length > 0 && Object.keys(COMPANIES).length === 0) { COMPANIES = window.COMPANIES; }
    var sameCompanyNPCs = getSameCompanyNPCs();
    if (Object.keys(COMPANIES).length === 0 && (!window.COMPANIES || Object.keys(window.COMPANIES).length === 0)) {
        container.innerHTML = '<div class="page active"><div class="page-header"><div class="back-btn" onclick="goToPage(&#39;home&#39;)">‹ 首页</div><div class="page-title">恋爱</div><div style="width:32px;"></div></div><div class="page-content" style="text-align:center;padding-top:60px;"><div style="color:var(--color-text-light);">数据加载中...</div></div></div>';
        __waitForCOMPANIES(function() { render(); });
        return;
    }
    var view = window._loveView || 'list';
    if (view === 'chat' && window._loveChatTarget) {
        _renderLoveChatView(container, window._loveChatTarget, sameCompanyNPCs);
    } else {
        _renderLoveListView(container, sameCompanyNPCs);
    }
    } catch(e) {
        console.error('Love app render error:', e); // debug overlay disabled for love app errors
        container.innerHTML = '<div class="page active"><div class="page-header"><div class="back-btn" onclick="goToPage(&#39;home&#39;)">‹ 首页</div><div class="page-title">恋爱</div><div style="width:32px;"></div></div><div class="page-content" style="text-align:center;padding-top:60px;"><div style="color:var(--color-primary);font-size:15px;font-weight:600;">加载遇到问题</div><div style="color:var(--color-text-light);font-size:12px;margin-top:8px;">点击返回首页</div><button onclick="currentPage=&#39;home&#39;;window._loveView=&#39;list&#39;;window._loveChatTarget=&#39;&#39;;render();renderBottomNav()" style="margin-top:16px;padding:10px 24px;background:var(--color-primary);color:white;border:none;border-radius: 12px;font-size:14px;">返回首页</button></div></div>';
    }
}


