function sendLoveGift(giftName, price, loveVal) {
    var target = window._loveChatTarget;
    if (!target) return;
    if (gameState.money < price) { showToast('金币不足'); return; }
    if (!gameState.loveChats) gameState.loveChats = {};
    if (!gameState.loveChats[target]) gameState.loveChats[target] = [];
    if (!gameState.npc好感度) gameState.npc好感度 = {};
    var now = new Date();
    var h = now.getHours(); var m = now.getMinutes();
    var ts = (h < 10 ? '0' : '') + h + ':' + (m < 10 ? '0' : '') + m;
    gameState.money -= price;
    addLove(target, loveVal);
    gameState.loveChats[target].push({ fromMe: true, text: '[送出 ' + giftName + ']', time: ts });
    var panel = document.getElementById('loveGiftPanel');
    if (panel) panel.style.display = 'none';
    if (!gameState._loveReplyQueue) gameState._loveReplyQueue = {};
    if (!gameState._loveReplyQueue[target]) gameState._loveReplyQueue[target] = 0;
    gameState._loveReplyQueue[target]++;
    var giftQueueId = gameState._loveReplyQueue[target];
    var npcName = target;
    // V1.7: AI-powered gift reply
    setTimeout(function() {
        if (gameState._loveReplyQueue[npcName] === giftQueueId) {
            var personalityReaction = getGiftReaction(npcName, giftName);
            if (canUseAIToday()) {
                window._aiNpcName = npcName;
                var giftCtx = npcName + '收到' + gameState.player.name + '送的' + giftName + '，非常开心';
                getAIReply('dating', giftCtx, '收到礼物了', function(aiReply) {
                    if (!gameState.loveChats[npcName]) gameState.loveChats[npcName] = [];
                    var now2 = new Date();
                    var h2 = now2.getHours(); var m2 = now2.getMinutes();
                    var ts2 = (h2 < 10 ? '0' : '') + h2 + ':' + (m2 < 10 ? '0' : '') + m2;
                    gameState.loveChats[npcName].push({ fromMe: false, text: aiReply, time: ts2 });
                    render();
                });
            } else if (personalityReaction) {
                if (!gameState.loveChats[npcName]) gameState.loveChats[npcName] = [];
                var now2 = new Date();
                var h2 = now2.getHours(); var m2 = now2.getMinutes();
                var ts2 = (h2 < 10 ? '0' : '') + h2 + ':' + (m2 < 10 ? '0' : '') + m2;
                gameState.loveChats[npcName].push({ fromMe: false, text: personalityReaction, time: ts2 });
                render();
            }
        }
    }, 1500);
    showToast('送出 ' + giftName + ' +' + loveVal + ' 好感度');
    render();
}

function getSameCompanyNPCs() {
    var npcs = [];
    if (window.COMPANIES && Object.keys(window.COMPANIES).length > 0 && Object.keys(COMPANIES).length === 0) { COMPANIES = window.COMPANIES; }
    var company = _getCompany(gameState.player.company);
    if (!company) return npcs;
    var keys = Object.keys(company.groups);
    for (var k = 0; k < keys.length; k++) {
        var group = company.groups[keys[k]];
        for (var m = 0; m < group.members.length; m++) {
            if (group.members[m].name !== gameState.player.name) {
                npcs.push(group.members[m]);
            }
        }
    }
    return npcs;
}

function npcDate(name) {
    if (!gameState.npc好感度 || (gameState.npc好感度[name] || 0) < 60) {
        showModal('好感度不足', '需要好感度达到60才能在一起');
        return;
    }
    _trackWeeklyGoal('date', 1);
    gameState.dating = name;
    showModal('在一起了！', '你和 ' + name + ' 正式在一起了！');
    render();
}

