function _restoreNav() {
    var nav = document.getElementById('bottomNav');
    var rest = document.getElementById('restButtons');
    if (nav) nav.style.display = 'flex';
    if (rest) rest.style.display = 'flex';
}

function toggleBubbleStickerPanel() {
    var panel = document.getElementById('bubbleStickerPanel');
    if (!panel) return;
    if (panel.style.display === 'none') {
        var html = '';
        for (var si = 0; si < gameState.bubbleStickers.length; si++) {
            var sn = gameState.bubbleStickers[si];
            var stickerData = null;
            for (var sj = 0; sj < STICKER_PACKS.length; sj++) {
                if (STICKER_PACKS[sj].name === sn) { stickerData = STICKER_PACKS[sj]; break; }
            }
            if (stickerData && stickerData.icon) {
                html += '<div style="display:inline-block;width:48px;height:48px;margin:4px;cursor:pointer;" onclick="send泡泡Sticker(\'' + sn.replace(/'/g, "\\'") + '\')"><img src="' + stickerData.icon + '" style="width:48px;height:48px;border-radius:8px;"></div>';
            } else {
                html += '<div style="display:inline-block;padding:6px 10px;margin:4px;background:var(--bg-card);border:1px solid var(--color-border);border-radius:8px;cursor:pointer;font-size:12px;" onclick="send泡泡Sticker(\'' + sn.replace(/'/g, "\\'") + '\')">' + sn + '</div>';
            }
        }
        if (!html) html = '<div style="text-align:center;color:var(--color-text-light);padding:12px;font-size:12px;">暂无表情包</div>';
        panel.innerHTML = html;
        panel.style.display = 'block';
    } else {
        panel.style.display = 'none';
    }
}

function send泡泡Sticker(name) {
    if (!bubbleChatTarget) return;
    if (!gameState.bubbleChats) gameState.bubbleChats = {};
    if (!gameState.bubbleChats[bubbleChatTarget]) gameState.bubbleChats[bubbleChatTarget] = [];
    gameState.bubbleChats[bubbleChatTarget].push({ fromMe: true, text: '[' + name + ']' });
    var panel = document.getElementById('bubbleStickerPanel');
    if (panel) panel.style.display = 'none';
    render泡泡Page(document.getElementById('app'));
}

function render泡泡Page(container) {
    if (!gameState.bubbleUnread) gameState.bubbleUnread = 0;
    if (!gameState.bubbleChats) gameState.bubbleChats = {};
    if (!gameState.bubble已发送) gameState.bubble已发送 = [];
    if (!gameState.bubbleStickers) gameState.bubbleStickers = [];
    var currentTab = window._bubbleTab || 'inbox';
    var tabBtns = '<div style="display:flex;gap:6px;margin-bottom:12px;">'
        + '<button class="btn btn-sm ' + (currentTab === 'inbox' ? 'btn-primary' : 'btn-secondary') + '" onclick="window._bubbleTab=\'inbox\';render();" style="flex:1;">收件箱</button>'
        + '<button class="btn btn-sm ' + (currentTab === 'sent' ? 'btn-primary' : 'btn-secondary') + '" onclick="window._bubbleTab=\'sent\';render();" style="flex:1;">已发送</button>'
        + '<button class="btn btn-sm ' + (currentTab === 'stickers' ? 'btn-primary' : 'btn-secondary') + '" onclick="window._bubbleTab=\'stickers\';render();" style="flex:1;">表情包商店</button>'
        + '</div>';

    var contentHtml = '';
    if (currentTab === 'inbox') {
        var messages = bubbleMultilangMessages;
        var allMsgs = [];
        for (var i = 0; i < messages.length; i++) {
            var m = messages[i];
            var langTag = m.lang === 'ko' ? 'KO' : m.lang === 'ja' ? 'JP' : m.lang === 'zh' ? 'CN' : 'EN';
            var langColor = m.lang === 'ko' ? '#1A2A3A' : m.lang === 'ja' ? '#7EC8E3' : m.lang === 'zh' ? '#4CD964' : '#FFD700';
            allMsgs.push({ type: 'fan', idx: i, from: m.from, text: m.orig, zhText: m.zh, langTag: langTag, langColor: langColor, time: m.time });
        }
        if (gameState.bubble已发送) {
            for (var si = 0; si < gameState.bubble已发送.length; si++) {
                var sm = gameState.bubble已发送[si];
                allMsgs.push({ type: 'me', text: sm.text, time: sm.time, to: sm.to || '' });
            }
        }
        for (var i = 0; i < allMsgs.length; i++) {
            var msg = allMsgs[i];
            if (msg.type === 'fan') {
                var isSelected = gameState._bubbleReplyTo === msg.idx;
                contentHtml += '<div style="display:flex;align-items:flex-start;gap:6px;margin-bottom:8px;padding:2px 0;cursor:pointer;' + (isSelected ? 'background:rgba(26,42,58,0.08);border-radius:8px;' : '') + '" onclick="gameState._bubbleReplyTo=' + msg.idx + ';render();">'
                    + '<div style="width:26px;height:26px;border-radius:50%;background:linear-gradient(135deg,' + msg.langColor + ',rgba(255,255,255,0.3));display:flex;align-items:center;justify-content:center;font-size:9px;color:white;font-weight:700;flex-shrink:0;">' + msg.from.charAt(0).toUpperCase() + '</div>'
                    + '<div style="flex:1;max-width:72%;">'
                    + '<div style="display:flex;align-items:center;gap:3px;margin-bottom:2px;">'
                    + '<span style="font-weight:600;font-size:10px;">' + msg.from + '</span>'
                    + '<span style="font-size:7px;padding:1px 3px;border-radius:2px;background:' + msg.langColor + ';color:white;font-weight:500;">' + msg.langTag + '</span>'
                    + '<span style="font-size:8px;color:var(--color-text-light);">' + msg.time + '</span></div>'
                    + '<div style="background:var(--bg-card);padding:7px 10px;border-radius:2px 12px 12px 12px;font-size:12px;line-height:1.5;box-shadow:0 1px 2px rgba(0,0,0,0.04);" id="bubbleMsg' + msg.idx + '">' + msg.text + ' <span class="translate-btn" onclick="event.stopPropagation();translateBubbleMsg(' + msg.idx + ')">翻译</span></div>'
                    + '</div></div>';
            } else {
                contentHtml += '<div style="display:flex;justify-content:flex-end;margin-bottom:8px;padding:2px 0;">'
                    + '<div style="max-width:72%;">'
                    + '<div style="text-align:right;font-size:8px;color:var(--color-text-light);margin-bottom:2px;">' + (msg.to ? '回复 ' + msg.to + ' ' : '') + msg.time + '</div>'
                    + '<div style="background:var(--color-primary);color:white;padding:7px 10px;border-radius:12px 2px 12px 12px;font-size:12px;line-height:1.5;">' + msg.text + '</div>'
                    + '</div></div>';
            }
        }
        if (allMsgs.length === 0) {
            contentHtml = '<div style="text-align:center;color:var(--color-text-light);padding:40px 20px;">暂无消息</div>';
        }
        } else if (currentTab === 'sent') {
        if (gameState.bubble已发送 && gameState.bubble已发送.length > 0) {
            for (var si = 0; si < gameState.bubble已发送.length; si++) {
                var sm = gameState.bubble已发送[si];
                contentHtml += '<div class="card" style="padding:12px;">'
                    + '<div style="display:flex;justify-content:space-between;margin-bottom:4px;">'
                    + '<span style="font-weight:600;color:var(--color-primary);font-size:13px;">回复给 ' + sm.to + '</span>'
                    + '<span style="font-size:10px;color:var(--color-text-light);">' + sm.time + '</span>'
                    + '</div>'
                    + '<p style="font-size:14px;">' + sm.text + '</p></div>';
            }
        }
        if (!contentHtml) contentHtml = '<p style="text-align:center;color:var(--color-text-light);padding:40px 20px;">暂无已发送消息</p>';
    } else if (currentTab === 'stickers') {
        var stickerPacks = [
            { name: '可爱猫咪', price: 3000, count: 8, color: '#1A2A3A', icon: 'https://linyangjie1015.github.io/my-idol/imgs/sticker_icon_0.jpg' },
            { name: '韩系表情', price: 5000, count: 12, color: '#7C4DFF', icon: 'https://linyangjie1015.github.io/my-idol/imgs/sticker_icon_1.jpg' },
            { name: '爱豆日常', price: 8000, count: 16, color: '#4CD964', icon: 'https://linyangjie1015.github.io/my-idol/imgs/sticker_icon_2.jpg' },
            { name: '粉丝应援', price: 6000, count: 10, color: '#FFD700', icon: 'https://linyangjie1015.github.io/my-idol/imgs/sticker_icon_3.jpg' },
            { name: '泡泡专属', price: 10000, count: 20, color: '#94A3B8', icon: 'https://linyangjie1015.github.io/my-idol/imgs/sticker_icon_4.jpg' }
        ];
        for (var pi = 0; pi < stickerPacks.length; pi++) {
            var sp = stickerPacks[pi];
            var owned = gameState.bubbleStickers && gameState.bubbleStickers.indexOf(sp.name) >= 0;
            contentHtml += '<div class="card" style="display:flex;align-items:center;gap:12px;">'
                + '<div style="width:48px;height:48px;border-radius:12px;overflow:hidden;"><img src="' + sp.icon + '" style="width:100%;height:100%;object-fit:cover;border-radius:12px;"></div>'
                + '<div style="flex:1;">'
                + '<div style="font-weight:600;font-size:14px;">' + sp.name + '</div>'
                + '<div style="font-size:12px;color:var(--color-text-light);">' + sp.count + '个表情</div>'
                + '</div>'
                + (owned ? '<span style="color:var(--color-success);font-weight:600;font-size:12px;">已拥有</span>'
                   : '<button class="btn btn-sm btn-primary" onclick="buyStickerPack(\'' + sp.name + '\',' + sp.price + ')">' + sp.price.toLocaleString() + '金币</button>')
                + '</div>';
        }
    }

    var replyBar = '';
    if (currentTab === 'inbox') {
        var replyTarget = gameState._bubbleReplyTo;
        var replyLabel = '';
        if (replyTarget !== undefined && replyTarget !== null && bubbleMultilangMessages[replyTarget]) {
            replyLabel = '<div style="display:flex;align-items:center;gap:6px;padding:6px 12px;background:rgba(26,42,58,0.1);border-radius:8px 8px 0 0;font-size:11px;color:var(--color-primary);"><span>回复 ' + bubbleMultilangMessages[replyTarget].from + '</span><span onclick="gameState._bubbleReplyTo=null;render();" style="margin-left:auto;cursor:pointer;color:var(--color-text-light);font-size:14px;">X</span></div>';
        }
        replyBar = '<div style="flex-shrink:0;padding:8px 12px;background:var(--color-bg);border-top:1px solid var(--color-border);">'
            + replyLabel
            + '<div style="display:flex;gap:8px;">'
            + '<input type="text" id="bubbleFixedInput" placeholder="输入消息..." style="flex:1;font-size:13px;padding:10px 14px;border:1px solid var(--color-border);border-radius: 12px;background:var(--bg-main);" onkeydown="if(event.key===\'Enter\')sendBubbleFixedReply()">'
            + '<button class="btn btn-sm btn-primary" onclick="sendBubbleFixedReply()" style="padding:10px 16px;border-radius: 12px;font-size:13px;">发送</button>'
            + '</div></div>';
    }
    container.innerHTML = '<div class="page active" style="display:flex;flex-direction:column;height:100%;">'
        + '<div class="page-header" style="flex-shrink:0;">'
        + '<div class="back-btn" onclick="goToPage(\'home\')">\u2039 首页</div>'
        + '<div class="page-title">泡泡</div>'
        + '<div style="width:32px;"></div>'
        + '</div>'
        + '<div style="flex:1;overflow-y:auto;padding:0 16px;">'
        + tabBtns
        + '<div id="bubbleContent">'
        + contentHtml
        + '</div>'
        + '</div>'
        + replyBar
        + getAppLinkHtml('fancommunity')
        + '</div>';
}

function sendBubbleFixedReply() {
    var input = document.getElementById('bubbleFixedInput');
    if (!input || !input.value.trim()) return;
    var text = input.value.trim();
    var replyTarget = gameState._bubbleReplyTo;
    var to = '';
    if (replyTarget !== undefined && replyTarget !== null && bubbleMultilangMessages[replyTarget]) {
        to = bubbleMultilangMessages[replyTarget].from;
    }
    input.value = '';
    if (!gameState.bubble已发送) gameState.bubble已发送 = [];
    gameState.bubble已发送.unshift({ to: to, text: text, time: new Date().toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' }) });
    gameState.fans += Math.floor(Math.random() * 5) + 1;
    gameState.fame = (gameState.fame || 30) + 1;
    gameState._bubbleReplyTo = null;
    showToast(to ? '已回复 ' + to : '已发送');
    triggerSilentSave();
    render();
}

function sendBubbleInboxReply(idx) {
    gameState._bubbleReplyTo = idx;
    sendBubbleFixedReply();
}

function buyStickerPack(name, price) {
    if (gameState.money < price) { showToast('金币不足'); return; }
    if (!gameState.bubbleStickers) gameState.bubbleStickers = [];
    if (gameState.bubbleStickers.indexOf(name) >= 0) { showToast('已拥有该表情包'); return; }
    showModal('购买表情包', '确认购买「' + name + '」？\n价格: ' + price.toLocaleString() + ' 金币', [
        { text: '取消', action: closeModal },
        { text: '确认', action: function() {
            gameState.money -= price;
            gameState.bubbleStickers.push(name);
            closeModal();
            showToast('已购买「' + name + '」');
            triggerSilentSave();
            render();
        }}
    ]);
}

function showBubblePlusMenu() {
    var stickerHtml = '';
    if (gameState.bubbleStickers && gameState.bubbleStickers.length > 0) {
        stickerHtml = '<div style="font-weight:600;margin-bottom:8px;">我的表情包</div>';
        for (var si = 0; si < gameState.bubbleStickers.length; si++) {
            var sn = gameState.bubbleStickers[si];
            stickerHtml += '<div class="card" style="padding:10px;cursor:pointer;margin-bottom:6px;" onclick="insertBubbleSticker(\'' + sn + '\')">'
                + '<div style="font-size:13px;">[' + sn + ']</div></div>';
        }
    }
    showModal('添加内容', stickerHtml + '<div style="font-size:12px;color:var(--color-text-light);margin-top:8px;">更多内容开发中...</div>', [
        { text: '关闭', action: closeModal }
    ]);
}

function insertBubbleSticker(name) {
    var input = document.getElementById('bubbleInboxInput');
    if (input) input.value = '[' + name + '] ';
    closeModal();
}

function translateBubbleMsg(idx) {
    var el = document.getElementById('bubbleMsg' + idx);
    if (!el) return;
    var zhText = bubbleMultilangMessages[idx] ? bubbleMultilangMessages[idx].zh : '';
    if (el.getAttribute('data-translated') === '1') {
        el.innerHTML = bubbleMultilangMessages[idx].orig + ' <span class="translate-btn" onclick="translateBubbleMsg(' + idx + ')">翻译</span>';
        el.setAttribute('data-translated', '0');
    } else {
        el.innerHTML = zhText + ' <span class="translate-btn" onclick="translateBubbleMsg(' + idx + ')">原文</span>';
        el.setAttribute('data-translated', '1');
    }
}

