        + '<div style="background:rgba(0,0,0,0.15);border-radius:12px;padding:10px;">'
        + '<div style="font-size:9px;color:rgba(255,255,255,0.7);margin-bottom:4px;text-align:center;">ABILITY</div>'
        + abilityHtml
