function showNpcCard(npcName) {
    if (!npcName) return;
    var npc = null;
    for (var i = 0; i < gameState.kakaoFriends.length; i++) {
        if (gameState.kakaoFriends[i].name === npcName) { npc = gameState.kakaoFriends[i]; break; }
    }
    if (!npc) return;
    var 好感 = (gameState.npc好感度 && gameState.npc好感度[npcName]) || 0;
    var hiddenOk = 好感 >= 30;
    var html = '<div style="position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.5);z-index:9999;display:flex;align-items:center;justify-content:center;" onclick="if(event.target===this)this.remove()">'
        + '<div style="background:var(--bg-card);border-radius: 12px;width:85%;max-width:340px;padding:24px;box-shadow:0 20px 60px rgba(0,0,0,0.3);" onclick="event.stopPropagation()">'
        + '<div style="display:flex;align-items:center;margin-bottom:16px;">'
        + '<div style="width:56px;height:56px;border-radius:50%;background:'+npc.avatarColor+';display:flex;align-items:center;justify-content:center;font-size:22px;color:white;font-weight:700;">'+npc.name.charAt(0)+'</div>'
        + '<div style="margin-left:14px;flex:1;">'
        + '<div style="font-size:18px;font-weight:700;color:var(--color-text);">'+npc.name+'</div>'
        + '<div style="font-size:11px;color:var(--color-text-light);margin-top:2px;">'+(npc.specialty||'')+(npc.specialty&&npc.personality?' | ':'')+(npc.personality||'')+'</div>'
        + (npc.isTeammate ? '<div style="font-size:9px;color:var(--color-primary);margin-top:1px;">队友</div>' : '')
        + '</div>'
        + '<div style="cursor:pointer;font-size:24px;color:var(--color-text-light);padding:4px 8px;line-height:1;" onclick="this.closest(\'div[style*=position:fixed]\').remove()">&times;</div>'
        + '</div>';
    if (npc.bio) {
        html += '<div style="margin-bottom:12px;"><div style="font-size:11px;color:var(--color-text-light);margin-bottom:4px;">简介</div>'
            + '<div style="font-size:13px;color:var(--color-text);line-height:1.6;">'+npc.bio+'</div></div>';
    }
    if (npc.quote) {
        html += '<div style="margin-bottom:12px;padding:10px 14px;background:#F8FAFC;border-radius:10px;">'
            + '<div style="font-size:11px;color:var(--color-primary);margin-bottom:4px;">招牌语</div>'
            + '<div style="font-size:13px;color:var(--color-text);font-style:italic;">\u201c'+npc.quote+'\u201d</div></div>';
    }
    // V1.7: Enhanced affection bar with milestone markers
    var milestoneHtml = '';
    var milestones = HIDDEN_DIALOGUES[npcName] || [];
    for (var mi = 0; mi < milestones.length; mi++) {
        var ms = milestones[mi];
        var msReached = 好感 >= ms.level;
        var msLeft = Math.max(0, ms.level - 好感);
        milestoneHtml += '<div style="display:flex;align-items:center;gap:6px;margin-bottom:6px;padding:6px 8px;border-radius:8px;background:'+(msReached?'linear-gradient(135deg,#F8FAFC,#E2E8F0)':'#F5F5F5')+';'+(msReached?'cursor:pointer;touch-action:manipulation;-webkit-tap-highlight-color:transparent;':'')+'"'+(msReached?' onclick="viewHiddenDialogue(\''+npcName.replace(/'/g,"\\'")+'\','+ms.level+')"':'')+'>'
            + '<div style="width:18px;height:18px;border-radius:50%;font-size:9px;display:flex;align-items:center;justify-content:center;font-weight:700;color:white;flex-shrink:0;background:'+(msReached?'linear-gradient(135deg,#1A2A3A,#1E293B)':'#CCC')+';">'+ms.level+'</div>'
            + '<div style="flex:1;">'
            + '<div style="font-size:11px;color:'+(msReached?'var(--color-primary)':'var(--color-text-light)')+';font-weight:'+(msReached?'600':'400')+';">'+ms.title+'</div>'
            + (msReached ? '<div style="font-size:10px;color:var(--color-text-light);margin-top:1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">'+ms.dialogue.substring(0,25)+'...</div>' : '<div style="font-size:10px;color:var(--color-text-light);margin-top:1px;">还需'+msLeft+'好感度</div>')
            + '</div></div>';
    }

    var isDatingNpc = gameState.dating === npcName;
    html += '<div style="margin-bottom:12px;">' + _renderLoveProgressBar(好感, isDatingNpc) + '</div>';

    // V1.7: Show unlocked hidden dialogues
    if (milestoneHtml) {
        html += '<div style="margin-bottom:12px;"><div style="font-size:11px;color:var(--color-text-light);margin-bottom:8px;">秘密档案</div>' + milestoneHtml + '</div>';
    }

    // Keep backward compat: if npc has hidden but no HIDDEN_DIALOGUES entry
    if (npc.hidden && !HIDDEN_DIALOGUES[npcName] && 好感 >= 30) {
        html += '<div style="padding:10px 14px;background:linear-gradient(135deg,var(--bg-card),var(--color-secondary));border-radius:10px;">'
            + '<div style="font-size:11px;color:var(--color-primary);margin-bottom:4px;">隐藏特质</div>'
            + '<div style="font-size:13px;color:var(--color-text);line-height:1.6;">'+npc.hidden+'</div></div>';
    }
    html += '</div></div>';
    var overlay = document.createElement('div');
    overlay.innerHTML = html;
    document.body.appendChild(overlay);
}

function sendKakaoMessage() {
    var input = document.getElementById('kakaoMsgInput');
    if (!input) return;
    var text = input.value.trim();
    if (!text) return;

    var npcName = gameState.kakaoCurrentChat;
    if (!gameState.kakaoChats[npcName]) gameState.kakaoChats[npcName] = [];
    var now = new Date();
    var timeStr = (now.getHours() < 10 ? '0' : '') + now.getHours() + ':' + (now.getMinutes() < 10 ? '0' : '') + now.getMinutes();
    gameState.kakaoChats[npcName].push({ from: 'me', text: text, time: timeStr });

    input.value = '';

    // Immediately show sent message in DOM
    var area = document.getElementById('kakaoChatArea');
    if (area) {
        var sentDiv = document.createElement('div');
        sentDiv.className = 'kakao-msg-row me';
        sentDiv.innerHTML = '<div><div class="kakao-msg-bubble me">' + text + '</div><div class="kakao-msg-time">' + timeStr + '</div></div>';
        area.appendChild(sentDiv);
        area.scrollTop = area.scrollHeight;
    }

    var npc = null;
    for (var i = 0; i < gameState.kakaoFriends.length; i++) {
        if (gameState.kakaoFriends[i].name === npcName) { npc = gameState.kakaoFriends[i]; break; }
    }

    // Show typing indicator
    if (area) {
        var typingEl = document.createElement('div');
        typingEl.className = 'kakao-msg-row npc';
        typingEl.id = 'kakaoTypingIndicator';
        typingEl.innerHTML = '<div><div class="kakao-msg-bubble npc" style="color:var(--color-text-light);font-style:italic;">对方正在输入...</div></div>';
        area.appendChild(typingEl);
        area.scrollTop = area.scrollHeight;
    }

    var replyDelay = 1000 + Math.floor(Math.random() * 1500);
    setTimeout(function() {
        // Remove typing indicator
        var typing = document.getElementById('kakaoTypingIndicator');
        if (typing && typing.parentNode) typing.parentNode.removeChild(typing);
        
        if (npc) {
            var _npcPers = (npc.personality && npc.personality.join) ? npc.personality.join('/') : (npc.personality || '');
            var npcContext = npc.name + '(' + _npcPers + ')';
            if (npc.bio) npcContext += ' 背景：' + npc.bio;
            if (npc.quote) npcContext += ' 招牌语：' + npc.quote;
            if (npc.hidden) npcContext += ' 隐藏特质：' + npc.hidden;
            window._aiNpcName = npcName;
            getAIReply('kakaotalk', npcContext, text, function(reply) {
                gameState.kakaoChats[npcName].push({ from: 'npc', text: reply, time: timeStr });
                notifyKakao(npcName, reply.substring(0,30));
                var ca = document.getElementById('kakaoChatArea');
                if (ca) {
                    var npcDiv = document.createElement('div');
                    npcDiv.className = 'kakao-msg-row npc';
                    npcDiv.innerHTML = '<div><div class="kakao-msg-bubble npc">' + reply + '</div><div class="kakao-msg-time">' + timeStr + '</div></div>';
                    ca.appendChild(npcDiv);
                    ca.scrollTop = ca.scrollHeight;
                }
            });
        }
    }, replyDelay);

    if (area) area.scrollTop = area.scrollHeight;
}

