var _pageTimers = [];
function _addTimer(id) { _pageTimers.push(id); }
function _clearPageTimers() {
    for (var i = 0; i < _pageTimers.length; i++) {
        try { clearInterval(_pageTimers[i]); } catch(e) {}
        try { clearTimeout(_pageTimers[i]); } catch(e) {}
    }
    _pageTimers = [];
    if (liveDanmakuTimer) { clearInterval(liveDanmakuTimer); liveDanmakuTimer = null; }
    if (liveViewerTimer) { clearInterval(liveViewerTimer); liveViewerTimer = null; }
    if (restCountdown) { clearInterval(restCountdown); restCountdown = null; }
    isResting = false;
    isExamInProgress = false;
    if (speechRecognition) { try { speechRecognition.stop(); } catch(e) {} speechRecognition = null; }
    if (isLive) stopLive();
}

// Override goToPage to clear timers
var _origGoToPage = goToPage;
goToPage = function(page) {
    _clearPageTimers();
    try { _origGoToPage(page); } catch(e) {
        console.error('goToPage error:', e);
        window._inSceneMode = true;
        currentPage = 'home';
        try { render(); renderBottomNav(); } catch(e2) {}
    }
};

window.onerror = function(msg, url, line) {
    console.warn('Error:', msg, 'L' + line, url || '');
    // SyntaxError / Unexpected EOF: just log, don't disrupt the page
    // These often come from Safari partially caching large JS files
    if (msg && (msg.indexOf('SyntaxError') !== -1 || msg.indexOf('Unexpected EOF') !== -1)) {
        console.warn('JS parse error (non-blocking):', msg, url);
        // Clear caches silently for next reload
        if (typeof caches !== 'undefined') {
            try { caches.keys().then(function(ns) { for(var i=0;i<ns.length;i++) caches.delete(ns[i]); }); } catch(e) {}
        }
        return true; // suppress the error, don't navigate away
    }
    // For runtime errors, try to recover
    if (typeof gameState !== 'undefined' && gameState.player && gameState.player.name) {
        try {
            window._inSceneMode = true;
            currentPage = 'home';
            if (typeof render === 'function') { render(); renderBottomNav(); }
            showToast('出了点问题: ' + (msg || '').substring(0,30));
            return true;
        } catch(e) {}
    }
    // Last resort: show error page with recovery
    var _app = document.getElementById('app');
    if (_app) {
        _app.innerHTML = '<div style="padding:40px;text-align:center;color:var(--color-primary, #1E293B);">' +
            '<div style="font-size:18px;font-weight:700;">出了点问题</div>' +
            '<div style="font-size:12px;margin-top:8px;color:var(--color-text-light, #999);">' + (msg || '').substring(0, 50) + '</div>' +
            '<button onclick="currentPage=&#39;home&#39;;render();renderBottomNav()" style="margin-top:16px;padding:8px 20px;background:var(--color-primary, #1A2A3A);color:white;border:none;border-radius: 12px;">返回首页</button>' +
            '</div>';
    }
    return true;
};

