        + '</div>'
        + '</div>'
        + '<div class="section-title">\u5b58\u6863\u7ba1\u7406</div>'
        + '<div class="card" onclick="saveGame(current\u5b58\u6863)" style="cursor:pointer;">'
        + '<div style="font-weight:600;">\u4fdd\u5b58\u6e38\u620f</div>'
