        + '@keyframes v2-pulse{0%,100%{opacity:1}50%{opacity:0.6}}'
        + '@keyframes v2-affection-float{0%{opacity:1;transform:translateY(0)}100%{opacity:0;transform:translateY(-30px)}}'
        + '@keyframes v2-glow-gold{0%,100%{box-shadow:0 0 0 rgba(255,215,0,0)}50%{box-shadow:0 0 30px rgba(255,215,0,0.4)}}'
