      var un = love >= st.lv;
      html += '<div style="flex:1;padding:8px 4px;text-align:center;background:'+(un?n.color:'rgba(255,255,255,0.05)')+';border-radius:8px;'+(un?'cursor:pointer;':'opacity:0.4;')+'" '
