      + 'border-bottom:1px solid rgba(255,255,255,0.06);">'
      + '<div onclick="goToPage(\'home\')" style="color:rgba(255,255,255,0.5);font-size:14px;font-weight:300;cursor:pointer;">‹ 首页</div>'
