    var fanNames = ['月野兔', '星辰光', '小甜饼', '彩虹糖', '棉花糖', '星光酱', '樱桃子', '蜜桃酱', '小草莓', '布丁狗'];
    var reactionMsgs = ['哇！', '好棒！', '加油！', '爱你！', '太厉害了！', '比心！', '好可爱！', '再来一个！', '笑死', '感动'];
    var numReactions = Math.floor(Math.random() * 3) + 2;
